function setImageSrc(e){return e.onload=function(){this.classList.add("loaded")},e.src=e.getAttribute("data-img-src")}function checkIfBooksInViewport(){for(var e=document.getElementsByClassName("book-img"),n=0;n<e.length;n++){var t=e[n];if(!t.classList.contains("loaded")){var o=t.getBoundingClientRect();o.top>=0&&o.bottom<=(window.innerHeight||document.documentElement.clientHeight)&&setImageSrc(t)}}}var debouncedCheckIfBooksInViewport=debounce(function(){return checkIfBooksInViewport()},250);function debounce(e,n,t){var o;return function(){var c=this,i=arguments;clearTimeout(o),o=setTimeout(function(){o=null,t||e.apply(c,i)},n),t&&!o&&e.apply(c,i)}}document.addEventListener("DOMContentLoaded",function(){return window.onscroll=function(){debouncedCheckIfBooksInViewport()},checkIfBooksInViewport()});
